53	fn eval_tensor_expr(
54	    expr: &Expr,
55	    env: &mut Environment,
56	    tape: &Rc<Tape>,
57	    params: &HashMap<String, Tensor>,
58	) -> Result<Tensor, EvalError> {
59	    let leaf = |v: DenseArray| Tensor::leaf(Rc::clone(tape), v, false);
60	    match expr {
61	        Expr::IntLit(n, _) => Ok(leaf(DenseArray::from_scalar(*n as f64))),
62	        Expr::FloatLit(f, _) => Ok(leaf(DenseArray::from_scalar(*f))),
63	        Expr::Ident(name, _) => {
64	            if let Some(t) = params.get(name) {
65	                return Ok(t.clone());
66	            }
67	            let arr = env
68	                .get(name)
69	                .cloned()
70	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
71	            Ok(leaf(arr))
72	        }
73	        Expr::ArrayLit(elems, _) => {
74	            let arr = crate::eval_ops::eval_array_lit(elems, env, &mut None)?;
75	            Ok(leaf(arr))
76	        }
77	        Expr::UnaryNeg { operand, .. } => Ok(eval_tensor_expr(operand, env, tape, params)?.neg()),
78	        Expr::BinOp { op, lhs, rhs, .. } => {
79	            let l = eval_tensor_expr(lhs, env, tape, params)?;
80	            let r = eval_tensor_expr(rhs, env, tape, params)?;
81	            Ok(match op {
82	                BinOpKind::Add => l.add(&r),
83	                BinOpKind::Sub => l.sub(&r),
84	                BinOpKind::Mul => l.mul(&r),
85	                BinOpKind::Div => l.div(&r),
86	            })
87	        }
88	        Expr::FnCall { name, args, .. } => eval_tensor_fncall(name, args, env, tape, params),
89	        Expr::TensorCtor { shape, .. } => {
90	            let dims = eval_shape_dims(shape, env)?;
91	            Ok(leaf(DenseArray::zeros(Shape::new(dims))))
92	        }
93	        Expr::Assign { .. } | Expr::Repeat { .. } | Expr::StrLit(_, _) => Err(
94	            EvalError::Unsupported("grad: expression form not supported inside grad()".into()),
95	        ),
96	    }
97	}
